package main

import (
    "errors"
    "fmt"
)

// Standard return
func add(a, b int) int {
    return a + b
}

// Named return
func getDimensions() (width, height int) {
    width = 1920
    height = 1080
    return
}

// Error return
func safeDivide(a, b float64) (float64, error) {
    if b == 0 {
        return 0, errors.New("division by zero")
    }
    return a / b, nil
}

func main() {
    fmt.Println(add(5, 3))
    w, h := getDimensions()
    fmt.Println(w, h)
    result, err := safeDivide(10, 0)
    fmt.Println(result, err)
}
